import (
	"encoding/json"
	"html"
	"log"
	"net/http"
	"time"
)

type SearchAnalyticsEvent struct {
	Keyword   string    `json:"keyword"`
	Path      string    `json:"path"`
	UserAgent string    `json:"user_agent"`
	Timestamp time.Time `json:"timestamp"`
}

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	keyword := r.URL.Query().Get("keyword")

	event := SearchAnalyticsEvent{
		Keyword:   keyword,
		Path:      r.URL.Path,
		UserAgent: r.UserAgent(),
		Timestamp: time.Now().UTC(),
	}

	logAnalytics(event)

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	escapedKeyword := html.EscapeString(keyword)
	_, _ = w.Write([]byte(`<!DOCTYPE html>
<html lang="en">
<head>
	<meta charset="UTF-8">
	<meta name="viewport" content="width=device-width, initial-scale=1.0">
	<title>Product Search Results</title>
</head>
<body>
	<h2>Search Results: ` + escapedKeyword + `</h2>
</body>
</html>`))
}

func logAnalytics(event SearchAnalyticsEvent) {
	data, err := json.Marshal(event)
	if err != nil {
		log.Printf("failed to marshal analytics event: %v", err)
		return
	}
	log.Printf("analytics=%s", data)
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	log.Println("server listening on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

