package main

import (
	"encoding/json"
	"html"
	"log"
	"net/http"
	"time"
)

type SearchAnalyticsEvent struct {
	Keyword   string    `json:"keyword"`
	Path      string    `json:"path"`
	Timestamp time.Time `json:"timestamp"`
	UserAgent string    `json:"user_agent"`
	RemoteIP  string    `json:"remote_ip"`
}

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	keyword := r.URL.Query().Get("keyword")

	event := SearchAnalyticsEvent{
		Keyword:   keyword,
		Path:      r.URL.Path,
		Timestamp: time.Now().UTC(),
		UserAgent: r.UserAgent(),
		RemoteIP:  r.RemoteAddr,
	}

	if data, err := json.Marshal(event); err == nil {
		log.Printf("search_analytics=%s", data)
	} else {
		log.Printf("search_analytics_error=%v", err)
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	escapedKeyword := html.EscapeString(keyword)
	_, _ = w.Write([]byte(`<!DOCTYPE html>
<html lang="en">
<head>
	<meta charset="UTF-8">
	<meta name="viewport" content="width=device-width, initial-scale=1.0">
	<title>Product Search</title>
</head>
<body>
	<h2>Search Results: ` + escapedKeyword + `</h2>
</body>
</html>`))
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/search", HandleProductSearch)

	server := &http.Server{
		Addr:              ":8080",
		Handler:           mux,
		ReadHeaderTimeout: 5 * time.Second,
	}

	log.Println("Server listening on http://localhost:8080")
	if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		log.Fatal(err)
	}
}

