package main

import (
	"encoding/json"
	"html"
	"log"
	"net/http"
	"time"
)

type SearchAnalyticsEvent struct {
	Keyword   string    `json:"keyword"`
	Path      string    `json:"path"`
	Timestamp time.Time `json:"timestamp"`
	UserAgent string    `json:"user_agent"`
	RemoteAddr string   `json:"remote_addr"`
}

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	keyword := r.URL.Query().Get("keyword")

	event := SearchAnalyticsEvent{
		Keyword:    keyword,
		Path:       r.URL.Path,
		Timestamp:  time.Now().UTC(),
		UserAgent:  r.UserAgent(),
		RemoteAddr: r.RemoteAddr,
	}

	if data, err := json.Marshal(event); err == nil {
		log.Printf("search_analytics=%s", data)
	} else {
		log.Printf("search_analytics_error=%v", err)
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.WriteHeader(http.StatusOK)

	escapedKeyword := html.EscapeString(keyword)
	_, _ = w.Write([]byte("<!DOCTYPE html>\n"))
	_, _ = w.Write([]byte("<html lang=\"en\">\n"))
	_, _ = w.Write([]byte("<head>\n"))
	_, _ = w.Write([]byte("    <meta charset=\"UTF-8\">\n"))
	_, _ = w.Write([]byte("    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n"))
	_, _ = w.Write([]byte("    <title>Product Search</title>\n"))
	_, _ = w.Write([]byte("</head>\n"))
	_, _ = w.Write([]byte("<body>\n"))
	_, _ = w.Write([]byte("    <h2>Search Results: " + escapedKeyword + "</h2>\n"))
	_, _ = w.Write([]byte("</body>\n"))
	_, _ = w.Write([]byte("</html>\n"))
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	log.Println("server listening on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

