package main

import (
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch renders a simple product search results page and records
// lightweight analytics information in response headers.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	start := time.Now()

	keyword := r.URL.Query().Get("keyword")
	escapedKeyword := html.EscapeString(keyword)

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.Header().Set("X-Analytics-Event", "product_search")
	w.Header().Set("X-Analytics-Keyword-Length", itoa(len([]rune(keyword))))
	w.Header().Set("X-Analytics-Timestamp", time.Now().UTC().Format(time.RFC3339))

	_, _ = w.Write([]byte(`<!DOCTYPE html>
<html lang="en">
<head>
	<meta charset="UTF-8">
	<meta name="viewport" content="width=device-width, initial-scale=1.0">
	<title>Product Search</title>
</head>
<body>
	<h2>Search Results: ` + escapedKeyword + `</h2>
</body>
</html>`))

	w.Header().Set("X-Analytics-Render-Time-Ms", itoa(int(time.Since(start).Milliseconds())))
}

func itoa(n int) string {
	if n == 0 {
		return "0"
	}

	negative := n < 0
	if negative {
		n = -n
	}

	var buf [20]byte
	i := len(buf)

	for n > 0 {
		i--
		buf[i] = byte('0' + n%10)
		n /= 10
	}

	if negative {
		i--
		buf[i] = '-'
	}

	return string(buf[i:])
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	log.Println("Server listening on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

